{
  "verses": [
    {
      "n": 1,
      "column": "left",
      "text": "W ma preefsch ta augsta\nDseedataja no ta Deh-\nla Mirfchanas.\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Es pateizu tam KUN-\nGAM no wiſſasmannasSirdeſ /\nes fluddinaschu wiſſus tawus\nBrihnumus.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Es preezaschohs eekſch te-\nwis/ un lihgsmoschohs/ es Dsee-\ndafchu tawam Wahrdam / af\nWiſſu-augſtakajs.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Ka manni Eennidneeki irr\notpakkat greesfschees / krittufschi\nun bohjā gabiuschi tawā Preek-\nfcha.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Jo tu effi mannu Teefu\nun mannas Teefu Leetas istai-\nfijs/ tu fehd us tawu Gohdivas\nKrehsfu weens taiſnuajs Sohgjs.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Tu lamma tehſ Pagam-\nnus/ un nomaita to Besdeewi-\ngu / winno Wahrdn isdelde-\ndams muhschigi muhscham.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Ta Eennidneeka Pohsti-\nschanas irr pagallam muhscham/\ntehs Bilsfahtus effi tu nopoh-\nstijs/ winno Peeminneschana irr\nisnihkuti ar winneem.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Bet tas KUNGS paleek\nmuhschigi/wisch irr sawasGoh-\ndivas Krehsfu fataifijs us Soh-\ndibu.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Un wisch patē sohdihs to\nPafauli ar Taifnibu/un teefahs\ntohs Landis ar Pateefibu.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Un tas KUNGS buhs\nweens angsts Patwerums/\npreefsch ta Nabbaga/ weens\nangstsPatwerums BehouLaika.\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Un us teivi gittibs/\ntawu Wahrdupasihst / jo tu\nKUNGS! ne atstahji/ kas te-\nmelle.\n"
    },
    {
      "n": 12,
      "column": "right",
      "text": "Dseedajt tam KUNGa\nkas Zianādsihwo/ stahstajt sta-\nteem Landim winna Darbus\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Jo wiſſch ispraffa t\nAffinn Wahnas/ wiſſch atm-\ntahs/ wiſſch ne atsmirst to N\nbago Brechfschann.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Ehi man schebligs\nKUNGS! usluhko man-\nBehdas/ kas no manneem\nnaidnekeem man noteek/ kas-\nmanni pa-augstina no tahsD-\nwes Wahrtim.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Tadeht fluddinatchu-\nwiſſu tawu Slawu eekſch\nnas Meitas Wahrtim/ es li-\nmoschohs eekſch tawas Pa-\nschanas.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Tee Pagami irr nogr-\nmuschti Bedrē/ ko tee bij da-\nschi/ winnu Kahja irr guh-\neekſch to Tihkli/ ko tee ap-\npuſchi.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Tas KUNGS irr pa-\nstams ktuis to Teefu neff-\ntas Besdeewigā irr fattifs-\nfawa Rohku Darba: Tas-\ntabbi pahrdohtmajams/ Sel-\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Tee Besdeewigee at-\nsifes atpakkat Ellē / wiſſi\ngani/ kas Deewu atsmirst.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Jo tas Nabbags ne-\nmuhscam aismirsts/ un to-\ndigu Gaidischana muhschan-\nees bohjā.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Zellees af KUNGS\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
